from functools import lru_cache

@lru_cache(maxsize=None)
def is_win(n):
    for m in [1]:
        if n + m >= 16: return True
        if not is_win(n + m): return True
    if n * 2 >= 16: return True
    if not is_win(n * 2): return True
    return False

print(1 if is_win(5) else 2)

from functools import lru_cache

@lru_cache(maxsize=None)
def win(n):
    if n + 1 >= 10 or n + 3 >= 10:
        return True
    if not win(n + 1):
        return True
    if not win(n + 3):
        return True
    return False

result = []
for s in range(1, 10):
    if not win(s):
        result.append(str(s))
print(' '.join(result))

